'use client'

import AutoScroll from 'embla-carousel-auto-scroll'
import { useEffect, useState } from 'react'

import {
  Carousel,
  type CarouselApi,
  CarouselContent,
  CarouselItem,
} from '@/components/ui/carousel'
import { cn } from '@/lib/utils'

export interface LogoMarqueeItem {
  title: string
  url: string
}

export interface LogoMarqueeProps {
  items: LogoMarqueeItem[]
  className?: string
}

export function LogoMarquee({ items, className }: Readonly<LogoMarqueeProps>) {
  const [api, setApi] = useState<CarouselApi>()

  useEffect(() => {
    if (!api) return
    api.plugins()?.autoScroll?.play()
  }, [api])

  const normalizedItems =
    items.length < 8 ? [...items, ...items, ...items] : items

  const containerWidthClassName = cn('w-full max-w-6xl mx-auto px-4', className)

  if (!normalizedItems.length) return null

  return (
    <div className="relative w-full">
      <Carousel
        setApi={setApi}
        opts={{
          align: 'start',
          loop: true,
        }}
        plugins={[
          AutoScroll({
            speed: 0.5,
            startDelay: 1,
            stopOnMouseEnter: true,
            stopOnInteraction: false,
          }),
        ]}
        className="w-full"
        aria-label="Carrossel de logos"
      >
        <CarouselContent
          className={cn('flex items-center', containerWidthClassName)}
        >
          {normalizedItems.map((item, index) => (
            <CarouselItem
              key={`${item.title}-${index}`}
              className="basis-auto pl-15"
            >
              <div className="flex h-12 items-center">
                <img
                  src={item.url}
                  alt={item.title}
                  width={120}
                  height={32}
                  loading="lazy"
                  decoding="async"
                  className="h-8 w-auto object-contain opacity-60 grayscale transition-[opacity,filter] duration-300 ease-out hover:opacity-100 hover:grayscale-0 dark:invert"
                />
              </div>
            </CarouselItem>
          ))}
        </CarouselContent>
      </Carousel>

      <div className="from-background pointer-events-none absolute inset-y-0 left-0 w-16 bg-gradient-to-r to-transparent" />
      <div className="from-background pointer-events-none absolute inset-y-0 right-0 w-16 bg-gradient-to-l to-transparent" />
    </div>
  )
}

import { LogoMarquee, type LogoMarqueeProps } from './logo-marquee'

export function LogoMarqueeExample() {
  const values = {
    items: [
      {
        title: 'Supabase',
        url: 'https://cdn.brandfetch.io/idsSceG8fK/w/800/h/156/theme/dark/logo.png?c=1dxbfHSJFAPEGdCLU4o5B',
      },
      {
        title: 'Google',
        url: 'https://cdn.brandfetch.io/id6O2oGzv-/theme/dark/logo.svg?c=1dxbfHSJFAPEGdCLU4o5B',
      },
      {
        title: 'Shopify',
        url: 'https://cdn.brandfetch.io/idAgPm7IvG/theme/dark/logo.svg?c=1dxbfHSJFAPEGdCLU4o5B',
      },
      {
        title: 'Mongo',
        url: 'https://cdn.brandfetch.io/ideyyfT0Lp/theme/dark/logo.svg?c=1dxbfHSJFAPEGdCLU4o5B',
      },
      {
        title: 'LottieFiles',
        url: 'https://cdn.brandfetch.io/idEExqEvR9/theme/dark/logo.svg?c=1dxbfHSJFAPEGdCLU4o5B',
      },
    ],
  } satisfies LogoMarqueeProps

  return <LogoMarquee items={values.items} />
}
